27: /**
28:  * A key/value pair to be received from Kafka. This also consists of a topic name and
29:  * a partition number from which the record is being received, an offset that points
30:  * to the record in a Kafka partition, and a timestamp as marked by the corresponding ProducerRecord.
31:  * <p>
32:  *
33:  * <h3>Thread Safety</h3>
34:  * This consumer record is <b>not thread-safe</b>. Concurrent access to a {@code ConsumerRecord} instance by
35:  * multiple threads may result in undefined behavior, including but not limited to the following:
36:  * <ul>
37:  *   <li>Throwing {@link ConcurrentModificationException} (e.g., when concurrently modifying {@link #headers()}).</li>
38:  *   <li>Data corruption or logical errors (e.g., inconsistent state of {@code headers} or {@code value}).</li>
39:  *   <li>Visibility issues (e.g., modifications by one thread not being visible to another thread).</li>
40:  * </ul>
41:  *
42:  * <p>
43:  * In particular, the {@link #headers()} method returns a mutable collection of headers. If multiple
44:  * threads access or modify these headers concurrently, it may lead to race conditions or inconsistent
45:  * states. It is the responsibility of the user to ensure that multi-threaded access is properly synchronized.
46:  *
47:  * <p>
48:  * Refer to the {@link KafkaConsumer} documentation for more details on multi-threaded consumption and processing strategies.
49:  */
50: public class ConsumerRecord<K, V> {
51:     public static final long NO_TIMESTAMP = RecordBatch.NO_TIMESTAMP;
52:     public static final int NULL_SIZE = -1;
53: 
54:     private final String topic;
55:     private final int partition;
56:     private final long offset;
57:     private final long timestamp;
58:     private final TimestampType timestampType;
59:     private final int serializedKeySize;
60:     private final int serializedValueSize;
61:     private final Headers headers;
62:     private final K key;
63:     private final V value;
64:     private final Optional<Integer> leaderEpoch;
65:     private final Optional<Short> deliveryCount;
66: 
67:     /**
68:      * Creates a record to be received from a specified topic and partition (provided for
69:      * compatibility with Kafka 0.9 before the message format supported timestamps and before
70:      * serialized metadata were exposed).
71:      *
72:      * @param topic The topic this record is received from
73:      * @param partition The partition of the topic this record is received from
74:      * @param offset The offset of this record in the corresponding Kafka partition
75:      * @param key The key of the record, if one exists (null is allowed)
76:      * @param value The record contents
77:      */
78:     public ConsumerRecord(String topic,
79:                           int partition,
80:                           long offset,
81:                           K key,
82:                           V value) {
83:         this(topic, partition, offset, NO_TIMESTAMP, TimestampType.NO_TIMESTAMP_TYPE, NULL_SIZE, NULL_SIZE, key, value,
84:             new RecordHeaders(), Optional.empty());
85:     }
86: 
87:     /**
88:      * Creates a record to be received from a specified topic and partition.
89:      *
90:      * @param topic The topic this record is received from
91:      * @param partition The partition of the topic this record is received from
92:      * @param offset The offset of this record in the corresponding Kafka partition
93:      * @param timestamp The timestamp of the record.
94:      * @param timestampType The timestamp type
95:      * @param serializedKeySize The length of the serialized key
96:      * @param serializedValueSize The length of the serialized value
97:      * @param key The key of the record, if one exists (null is allowed)
98:      * @param value The record contents
99:      * @param headers The headers of the record
100:      * @param leaderEpoch Optional leader epoch of the record (may be empty for legacy record formats)
101:      */
102:     public ConsumerRecord(String topic,
103:                           int partition,
104:                           long offset,
105:                           long timestamp,
106:                           TimestampType timestampType,
107:                           int serializedKeySize,
108:                           int serializedValueSize,
109:                           K key,
110:                           V value,
111:                           Headers headers,
112:                           Optional<Integer> leaderEpoch) {
113:         this(topic, partition, offset, timestamp, timestampType, serializedKeySize, serializedValueSize, key, value,
114:             headers, leaderEpoch, Optional.empty());
115:     }
116: 
117:     /**
118:      * Creates a record to be received from a specified topic and partition.
119:      *
120:      * @param topic The topic this record is received from
121:      * @param partition The partition of the topic this record is received from
122:      * @param offset The offset of this record in the corresponding Kafka partition
123:      * @param timestamp The timestamp of the record.
124:      * @param timestampType The timestamp type
125:      * @param serializedKeySize The length of the serialized key
126:      * @param serializedValueSize The length of the serialized value
127:      * @param key The key of the record, if one exists (null is allowed)
128:      * @param value The record contents
129:      * @param headers The headers of the record
130:      * @param leaderEpoch Optional leader epoch of the record (may be empty for legacy record formats)
131:      * @param deliveryCount Optional delivery count of the record (may be empty when deliveries not counted)
132:      */
133:     public ConsumerRecord(String topic,
134:                           int partition,
135:                           long offset,
136:                           long timestamp,
137:                           TimestampType timestampType,
138:                           int serializedKeySize,
139:                           int serializedValueSize,
140:                           K key,
141:                           V value,
142:                           Headers headers,
143:                           Optional<Integer> leaderEpoch,
144:                           Optional<Short> deliveryCount) {
145:         if (topic == null)
146:             throw new IllegalArgumentException("Topic cannot be null");
147:         if (headers == null)
148:             throw new IllegalArgumentException("Headers cannot be null");
149: 
150:         this.topic = topic;
151:         this.partition = partition;
152:         this.offset = offset;
153:         this.timestamp = timestamp;
154:         this.timestampType = timestampType;
155:         this.serializedKeySize = serializedKeySize;
156:         this.serializedValueSize = serializedValueSize;
157:         this.key = key;
158:         this.value = value;
159:         this.headers = headers;
160:         this.leaderEpoch = leaderEpoch;
161:         this.deliveryCount = deliveryCount;
162:     }
163: 
164:     /**
165:      * The topic this record is received from (never null)
166:      */
167:     public String topic() {
168:         return this.topic;
169:     }
170: 
171:     /**
172:      * The partition from which this record is received
173:      */
174:     public int partition() {
175:         return this.partition;
176:     }
177: 
178:     /**
179:      * The headers (never null)
180:      */
181:     public Headers headers() {
182:         return headers;
183:     }
184:     
185:     /**
186:      * The key (or null if no key is specified)
187:      */
188:     public K key() {
189:         return key;
190:     }
191: 
192:     /**
193:      * The value
194:      */
195:     public V value() {
196:         return value;
197:     }
198: 
199:     /**
200:      * The position of this record in the corresponding Kafka partition.
201:      */
202:     public long offset() {
203:         return offset;
204:     }
205: 
206:     /**
207:      * The timestamp of this record, in milliseconds elapsed since unix epoch.
208:      */
209:     public long timestamp() {
210:         return timestamp;
211:     }
212: 
213:     /**
214:      * The timestamp type of this record
215:      */
216:     public TimestampType timestampType() {
217:         return timestampType;
218:     }
219: 
220:     /**
221:      * The size of the serialized, uncompressed key in bytes. If key is null, the returned size
222:      * is -1.
223:      */
224:     public int serializedKeySize() {
225:         return this.serializedKeySize;
226:     }
227: 
228:     /**
229:      * The size of the serialized, uncompressed value in bytes. If value is null, the
230:      * returned size is -1.
231:      */
232:     public int serializedValueSize() {
233:         return this.serializedValueSize;
234:     }
235: 
236:     /**
237:      * Get the leader epoch for the record if available
238:      *
239:      * @return the leader epoch or empty for legacy record formats
240:      */
241:     public Optional<Integer> leaderEpoch() {
242:         return leaderEpoch;
243:     }
244: 
245:     /**
246:      * Get the delivery count for the record if available. Deliveries
247:      * are counted for records delivered by share groups.
248:      *
249:      * @return the delivery count or empty when deliveries not counted
250:      */
251:     public Optional<Short> deliveryCount() {
252:         return deliveryCount;
253:     }
254: 
255:     @Override
256:     public String toString() {
257:         return "ConsumerRecord(topic = " + topic
258:                + ", partition = " + partition
259:                + ", leaderEpoch = " + leaderEpoch.orElse(null)
260:                + ", offset = " + offset
261:                + ", " + timestampType + " = " + timestamp
262:                + ", deliveryCount = " + deliveryCount.orElse(null)
263:                + ", serialized key size = "  + serializedKeySize
264:                + ", serialized value size = " + serializedValueSize
265:                + ", headers = " + headers
266:                + ", key = " + key
267:                + ", value = " + value + ")";
268:     }
269: }
